using UnityEngine;

/// <summary>
/// Define um mundo do jogo (ex: Floresta, Deserto, etc.) para uso em condições
/// de NPC (mundo actual, boss derrotado, regresso pós-boss).
/// </summary>
[CreateAssetMenu(menuName = "Animals/World Data", fileName = "NewWorld")]
public class WorldData : ScriptableObject
{
    [Header("Identidade")]
    public string worldId;
    public string displayName;

    [Header("Boss")]
    [Tooltip("Identificador do boss deste mundo (apenas informativo).")]
    public string bossId;

    [Header("Vila Principal")]
    [Tooltip("villageId da vila principal deste mundo (existe uma vila por mundo). Usado por WorldState.GetVillagePopulation/SetVillagePopulation e pelo HUD (população da vila) — as áreas obtêm a vila através de AreaData.world.mainVillageId, em vez de uma ligação presumida com AreaData.areaId.")]
    public string mainVillageId;

    [Header("Caminho do Ferimento")]
    [Tooltip("'Espírito Final' deste mundo (item especial — PlayerProgress.HasCollectedSpecialItem). Usado por Checkpoint.requiredSpiritItem: a sub-área correspondente do Caminho do Ferimento só guarda checkpoint de início se este item já tiver sido recolhido.")]
    public ItemData finalSpiritItem;

    [Header("Mapa-Múndi — Apresentação")]
    [Tooltip("Logo/emblema completo deste mundo. Mostrado: (1) no Coração de Gaia, junto aos outros 5, antes de escolher uma direcção; (2) em destaque, em ecrã cheio, na primeira vez que o jogador chega à 1ª área deste mundo (apresentação do mundo).")]
    public Sprite mapLogo;

    [Tooltip("Nome do mundo mostrado no topo do ecrã sempre que o jogador está dentro deste mundo no Mapa-Múndi (após a apresentação inicial desaparecer).")]
    public string mapWorldName;

    [Tooltip("Música/sting curto e exclusivo tocado durante a apresentação do mundo (1ª vez que se chega à 1ª área). Vazio = sem música extra.")]
    public AudioClip presentationMusic;

    [Tooltip("Frase temática opcional mostrada durante a apresentação do mundo, antes de desaparecer e deixar apenas o nome do mundo no topo. Vazio = não mostra frase.")]
    [TextArea]
    public string themePhrase;

    [Header("Mapa-Múndi — Cor das Raízes/Ramos")]
    [Tooltip("Cor base das raízes/ramos deste mundo no Mapa-Múndi (estado normal, antes de derrotar o boss).")]
    public Color rootColor = Color.white;

    [Tooltip("Cor das raízes/ramos deste mundo no Mapa-Múndi DEPOIS de derrotar o boss (mudança visual pós-boss — pode representar \"arame\" a desaparecer, luz a voltar, etc.). Usada por WorldMapConnection para interpolar a cor quando PlayerProgress.IsBossDefeated(world) for verdadeiro.")]
    public Color rootColorPostBoss = Color.white;

    [Header("Mapa-Múndi — Emblema do Mundo")]
    [Tooltip("Emblema do mundo mostrado no canto superior direito do HUD do Mapa-Múndi depois de o jogador o obter (ex: ao derrotar o boss). Enquanto não obtido, o espaço do emblema fica vazio/oculto.")]
    public EmblemData worldEmblem;

    [Header("Mapa-Múndi — Missão Principal (Desbloqueio do Boss)")]
    [Tooltip("Missão cuja conclusão liberta a área do Boss deste mundo no Mapa-Múndi (WorldMapController.CheckBossUnlocks). A área de Boss (AreaData.mapNodeType = Boss) nunca é comprada — fica acessível automaticamente quando MissionManager.IsMissionCompleted(mainMission) for verdadeiro.")]
    public MissionData mainMission;
}
